"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[1526],{4394:(n,a,s)=>{s.r(a),s.d(a,{data:()=>e});const e={key:"v-fb63021e",path:"/module/vue/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8C%87%E4%BB%A4.html",title:"",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"自定义指令传参",slug:"自定义指令传参",children:[]},{level:2,title:"防抖",slug:"防抖",children:[]},{level:2,title:"实用的自定义指令",slug:"实用的自定义指令",children:[]}],filePathRelative:"module/vue/自定义指令.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},6970:(n,a,s)=>{s.r(a),s.d(a,{default:()=>u});var e=s(6252);const t=(0,e.uE)('<h2 id="自定义指令传参" tabindex="-1"><a class="header-anchor" href="#自定义指令传参" aria-hidden="true">#</a> 自定义指令传参</h2><p>在main.js中定义一个指令。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>Vue<span class="token punctuation">.</span><span class="token function">directive</span><span class="token punctuation">(</span><span class="token string">&#39;zoom&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>\n    <span class="token function-variable function">bind</span><span class="token operator">:</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">el<span class="token punctuation">,</span> binding<span class="token punctuation">,</span> vnode</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>binding<span class="token punctuation">.</span>arg<span class="token punctuation">)</span> <span class="token comment">//     {a:1,b:2}</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token function-variable function">update</span><span class="token operator">:</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">el</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token function-variable function">unbind</span><span class="token operator">:</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">el</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>使用自定义指令，在任意一个html元素中，使用指令。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code># :{a:1,b:2} 为自定义参数 \n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name"><span class="token namespace">v-zoom:</span><span class="token namespace">{a:</span><span class="token namespace">1,b:</span>2}</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>{width: 800, height: 1000}<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li>方式一：v-zoom:{a:1,b:2}</li><li>对于{a:1,b:2}，在binding属性中，以字符串的形式传递，故可以写[1,2]、true等数据格式，但是最后拿到的都是字符串类型。</li><li>方式二：v-zoom=&quot;{width: 800, height: 1000}&quot;</li><li>等号后面的{width: 800, height: 1000}，可以在binding的value属性中获取的数据的类型没有变化，</li><li>可以直接使用。width后面的数字,可以用当前组件的参数替换。</li><li>方式三：v-zoom.a.b</li></ul><blockquote><p>除了 <code>el</code> 之外，其它参数都应该是只读的，切勿进行修改。如果需要在钩子之间共享数据，建议通过元素的 dataset 来进行。</p></blockquote><h2 id="防抖" tabindex="-1"><a class="header-anchor" href="#防抖" aria-hidden="true">#</a> 防抖</h2><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">v-debounce</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>addTag<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code>directives:{\n      debounce :{\n        inserted: function (el, binding,vnode,oldVnode) {\n          let timer\n          // 为当前绑定元素绑定点击事件\n          el.addEventListener(&#39;click&#39;, () =&gt; {\n          //清除上一次点击添加的定时器\n            if (timer) {\n              clearTimeout(timer)\n            }\n            let callNow = !timer\n            timer = setTimeout(() =&gt; {\n              timer=null\n            }, 1000)\n            //若点击不快则执行绑定的方法\n            if(callNow){\n              binding.value()\n            }\n          })\n        },\n      }\n    }\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h2 id="实用的自定义指令" tabindex="-1"><a class="header-anchor" href="#实用的自定义指令" aria-hidden="true">#</a> 实用的自定义指令</h2>',11),p={href:"https://segmentfault.com/a/1190000038475001",target:"_blank",rel:"noopener noreferrer"},l=(0,e.Uk)("分享8个非常实用的Vue自定义指令"),c={href:"https://juejin.cn/post/7112376862365450248",target:"_blank",rel:"noopener noreferrer"},o=(0,e.Uk)("我有一个牛逼的防抖，你要不要学"),i={},u=(0,s(3744).Z)(i,[["render",function(n,a){const s=(0,e.up)("OutboundLink");return(0,e.wg)(),(0,e.iD)(e.HY,null,[t,(0,e._)("p",null,[(0,e._)("a",p,[l,(0,e.Wm)(s)])]),(0,e._)("p",null,[(0,e._)("a",c,[o,(0,e.Wm)(s)])])],64)}]])},3744:(n,a)=>{a.Z=(n,a)=>{const s=n.__vccOpts||n;for(const[n,e]of a)s[n]=e;return s}}}]);